const input = ($input.all()[0] && $input.all()[0].json) || {};

let turnoId = null;
if (input.payload && input.payload.turno_id) {
  turnoId = input.payload.turno_id;
} else if (input.text) {
  const textLower = String(input.text).toLowerCase();
  const match = textLower.match(/\/cancelar\s+(\d+)/) || textLower.match(/cancelar:(\d+)/);
  if (match) {
    turnoId = match[1];
  }
}

return [{
  json: {
    chat_id: input.chat_id,
    turno_id: turnoId,
    text: input.text
  }
}];

const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const turnoId = input.turno_id || (input.id) || ($('Code - Extraer Turno ID').item && $('Code - Extraer Turno ID').item.json && $('Code - Extraer Turno ID').item.json.turno_id);

if (input.detail || (input.statusCode && input.statusCode >= 400)) {
  const statusCode = input.statusCode || 500;
  let mensaje = 'Error al cancelar el turno.';
  if (statusCode === 404) {
    mensaje = 'Turno no encontrado. Verificá el ID y probá de nuevo.';
  } else if (statusCode === 409) {
    mensaje = 'El turno ya fue cancelado previamente o no se puede cancelar en su estado actual.';
  } else if (input.detail) {
    mensaje = 'Error: ' + input.detail;
  }
  return [{
    json: {
      chat_id: chatId,
      turno_id: turnoId,
      exito: false,
      text: mensaje,
      buttons: []
    }
  }];
}

const fecha = input.fecha || '';
const hora = input.hora_inicio || '';

return [{
  json: {
    chat_id: chatId,
    turno_id: turnoId,
    exito: true,
    text: 'Turno #' + turnoId + ' cancelado exitosamente.' + (fecha ? '\n\nFecha: ' + fecha : '') + (hora ? '\nHora: ' + hora : '') + '\n\n¿Querés reprogramarlo?',
    buttons: [
      { label: 'Reprogramar este turno', value: 'reprogramar:' + turnoId }
    ]
  }
}];
